            runsScored: 0,
            ballsFaced: 0,
            fours: 0,
            sixes: 0,
            wicketsTaken: 0,
            oversBowled: 0,
            ballsBowled: 0,
            runsConceded: 0,
            maidens: 0,
            catches: 0,
            stumpings: 0,
            runOuts: 0,
            runOutAssists: 0,
