                attemptCount = (typeof pv.attempt_count === "number" ? pv.attempt_count : 0) + 1;
                firstAttemptMs = (typeof pv.first_attempt_ms === "number" && pv.first_attempt_ms > 0)
                    ? pv.first_attempt_ms : now;
